"""compose_convert - Preview quadlet files without installing."""

from utils import resolve_compose_path, prepare_compose, run_cmd


def compose_convert(
    compose_file: str | None = None, kube: bool = False, **_kwargs
) -> None:
    """Preview the quadlet files that would be generated by podlet.

    Runs podlet compose without --unit-directory so output goes to stdout.
    Uses the same defaults as up (--pod, --overwrite, --absolute-host-paths).
    """
    compose_path = resolve_compose_path(compose_file)

    # Ensure compose file has a `name` field (required by podlet --pod/--kube)
    podlet_input = prepare_compose(compose_path)

    # Build the same command as up, but without --unit-directory.
    # Note: --overwrite and --absolute-host-paths are global podlet
    # options and must precede the "compose" subcommand.
    # Pass the original compose directory to --absolute-host-paths so
    # relative paths resolve correctly (not from the temp file's location).
    compose_dir = str(compose_path.parent.resolve())
    cmd = [
        "podlet",
        "--overwrite",
        f"--absolute-host-paths={compose_dir}",
        "compose",
    ]
    if kube:
        cmd.append("--kube")
    else:
        cmd.append("--pod")
    cmd.append(str(podlet_input))

    result = run_cmd(cmd)
    if result.stdout:
        print(result.stdout, end="")
